globalThis.__BQ = {"mayozII":{"ilkokul":{"kolay":[{"q":"Mayoz I bittikten sonra kaç hücre oluşur ve bu hücreler Mayoz II ile ne yapar?","steps":[{"t":"Mayoz I sonucu","a":"2 hücre oluşur","d":"Mayoz I bölünmesi tamamlandığında bir ana hücreden 2 yeni hücre meydana gelir. Bu hücreler bir kez daha bölünmeye hazırlanır."},{"t":"Mayoz II başlar","a":"Her hücre tekrar bölünür","d":"Mayoz II evresinde bu 2 hücrenin her biri yeniden ikiye bölünür. Böylece toplam hücre sayısı artar."}],"ans":"Mayoz I sonunda 2 hücre oluşur ve Mayoz II ile bu hücreler tekrar bölünür."},{"q":"Mayoz II sonunda toplam kaç hücre oluşur?","steps":[{"t":"Başlangıç","a":"2 hücre vardır","d":"Mayoz II başlamadan önce elimizde Mayoz I'den gelen 2 hücre bulunur. Bunların her biri bölünecektir."},{"t":"Bölünme sonucu","a":"2 + 2 = 4 hücre","d":"Her bir hücre ikiye bölündüğü için 2 hücreden 4 hücre oluşur. Mayoz sonunda toplam 4 hücre meydana gelir."}],"ans":"Mayoz II sonunda toplam 4 hücre oluşur."},{"q":"Mayoz II sırasında DNA tekrar eşlenir mi?","steps":[{"t":"DNA eşlenmesi","a":"Hayır, eşlenmez","d":"Mayoz II başlamadan önce DNA yeniden kopyalanmaz. Hücre, var olan kalıtsal maddesiyle doğrudan bölünür."},{"t":"Sonuç","a":"Doğrudan bölünme","d":"DNA eşlenmediği için hücreler hemen bölünmeye geçer. Bu yüzden oluşan hücrelerde kalıtsal madde azalır."}],"ans":"Hayır, Mayoz II sırasında DNA tekrar eşlenmez."},{"q":"Mayoz II, hangi bölünmeye benzer?","steps":[{"t":"Benzerlik","a":"Mitoza benzer","d":"Mayoz II evresinde olaylar mitoz bölünmedeki gibi gerçekleşir. Kardeş parçalar birbirinden ayrılır."},{"t":"Neden","a":"Eşit ayrılma olur","d":"Mitozda olduğu gibi Mayoz II'de de kardeş kromatitler iki kutba çekilir. Bu yüzden iki bölünme birbirine benzetilir."}],"ans":"Mayoz II, mitoz bölünmeye benzer."},{"q":"Mayoz bölünme kaç bölünmeden oluşur?","steps":[{"t":"Birinci bölünme","a":"Mayoz I","d":"Mayozun ilk aşaması Mayoz I olarak adlandırılır. Burada ilk bölünme gerçekleşir."},{"t":"İkinci bölünme","a":"Mayoz II","d":"İkinci aşama ise Mayoz II'dir. Toplamda mayoz iki ardışık bölünmeden oluşur."}],"ans":"Mayoz bölünme iki bölünmeden (Mayoz I ve Mayoz II) oluşur."}],"zor":[{"q":"Bir ana hücreden Mayoz II sonunda neden 4 hücre oluştuğunu adım adım açıkla.","steps":[{"t":"İlk bölünme","a":"1 hücreden 2 hücre","d":"Mayoz I bölünmesiyle başlangıçtaki tek ana hücre 2 hücreye ayrılır. Bu ilk bölünmedir."},{"t":"İkinci bölünme","a":"2 hücreden 4 hücre","d":"Mayoz II ile bu 2 hücrenin her biri tekrar ikiye bölünür. Sonuçta hücre sayısı 4'e ulaşır."},{"t":"Toplam","a":"4 hücre","d":"İki ardışık bölünme sonucunda tek bir ana hücreden 4 yeni hücre meydana gelir. Bu mayozun temel sonucudur."}],"ans":"Mayoz I'de 2, Mayoz II'de bunlar bölünüp 4 hücre oluştuğu için toplam 4 hücre meydana gelir."},{"q":"Mayoz II sırasında DNA eşlenmediğine göre, bölünme sonunda kalıtsal madde nasıl değişir?","steps":[{"t":"DNA durumu","a":"Eşlenmez","d":"Mayoz II öncesinde DNA yeniden kopyalanmaz. Hücre mevcut kalıtsal maddesiyle bölünür."},{"t":"Bölünme","a":"Madde paylaşılır","d":"Var olan kalıtsal madde bölünen iki hücreye paylaştırılır. Her yeni hücreye daha az madde düşer."},{"t":"Sonuç","a":"Madde azalır","d":"Bu nedenle oluşan hücrelerdeki kalıtsal madde, başlangıçtaki hücreye göre azalmış olur. Üreme hücreleri bu şekilde oluşur."}],"ans":"DNA eşlenmediği için bölünmeyle kalıtsal madde paylaşılır ve her hücrede azalır."},{"q":"Mayoz II ile mitoz arasındaki en önemli benzerliği açıkla.","steps":[{"t":"Mitozda olay","a":"Kardeş parçalar ayrılır","d":"Mitozda kromozomların kardeş parçaları birbirinden ayrılarak iki kutba gider. Bu sayede eşit paylaşım olur."},{"t":"Mayoz II'de olay","a":"Aynı olay görülür","d":"Mayoz II'de de kardeş kromatitler birbirinden ayrılır. Bu davranış mitozdakiyle aynıdır."},{"t":"Benzerlik","a":"Kardeş parça ayrılması","d":"Her iki bölünmede de kardeş kromatitlerin ayrılması ortak özelliktir. Bu yüzden Mayoz II mitoza benzetilir."}],"ans":"Her ikisinde de kardeş kromatitlerin ayrılması ortak benzerliktir."},{"q":"Mayoz neden tek bir bölünme değil de iki bölünmeden oluşur?","steps":[{"t":"Amaç","a":"Madde yarıya iner","d":"Mayozun amacı üreme hücrelerindeki kalıtsal maddeyi yarıya indirmektir. Bu nedenle bölünme özel bir şekilde gerçekleşir."},{"t":"İki bölünme","a":"Mayoz I ve II","d":"Bir bölünmede eşler ayrılır, ikinci bölünmede kardeş parçalar ayrılır. İki adımla madde uygun şekilde paylaştırılır."},{"t":"Sonuç","a":"4 uygun hücre","d":"İki bölünme sonunda kalıtsal maddesi azalmış 4 üreme hücresi oluşur. Bu hücreler eşeyli üreme için gereklidir."}],"ans":"Kalıtsal maddeyi düzgün yarıya indirebilmek için mayoz iki ardışık bölünmeden oluşur."},{"q":"Mayoz II başında ana hücrede iki hücre olduğuna göre bu hücreler nereden gelmiştir?","steps":[{"t":"Köken","a":"Mayoz I'den","d":"Mayoz II'nin başında bulunan 2 hücre, Mayoz I bölünmesi sonucunda oluşmuştur. Bunlar ilk bölünmenin ürünüdür."},{"t":"Devam","a":"Tekrar bölünür","d":"Bu iki hücre Mayoz II ile yeniden bölünmeye girer. Her biri ikiye ayrılır."},{"t":"Sonuç","a":"4 hücre","d":"Mayoz I'den gelen 2 hücre Mayoz II ile 4 hücreye dönüşür. Böylece mayoz tamamlanmış olur."}],"ans":"Mayoz II başındaki iki hücre, Mayoz I bölünmesinden gelmiştir."}]},"ortaokul":{"kolay":[{"q":"Mayoz II'nin evrelerini sırasıyla yazınız.","steps":[{"t":"İlk iki evre","a":"Profaz II ve Metafaz II","d":"Mayoz II profaz II ile başlar, ardından metafaz II gelir. Profaz II'de kromozomlar belirginleşir, metafaz II'de ortada dizilirler."},{"t":"Son iki evre","a":"Anafaz II ve Telofaz II","d":"Sonra anafaz II'de kardeş kromatitler ayrılır, telofaz II'de hücreler tamamen ikiye bölünür. Böylece dört evre tamamlanır."}],"ans":"Profaz II, Metafaz II, Anafaz II ve Telofaz II."},{"q":"Mayoz II'nin anafaz II evresinde ne ayrılır?","steps":[{"t":"Anafaz II","a":"Ayrılma evresi","d":"Anafaz II, Mayoz II'nin ayrılma evresidir. Bu evrede kromozom yapıları kutuplara çekilir."},{"t":"Ayrılan yapı","a":"Kardeş kromatitler","d":"Anafaz II'de kardeş kromatitler birbirinden ayrılarak zıt kutuplara gider. Bu mitoz anafazına benzer."}],"ans":"Anafaz II evresinde kardeş kromatitler birbirinden ayrılır."},{"q":"Mayoz I sonunda oluşan hücrelerin kromozom durumu nasıldır?","steps":[{"t":"Mayoz I sonucu","a":"Haploid (n) hücreler","d":"Mayoz I sonunda oluşan iki hücre haploittir, yani kromozom sayısı yarıya inmiştir. Bunlar (n) olarak gösterilir."},{"t":"Mayoz II girişi","a":"n hücreler bölünür","d":"Bu haploid hücreler DNA eşlenmeden Mayoz II'ye girer. Kromozom sayıları (n) olarak kalır."}],"ans":"Mayoz I sonunda oluşan hücreler haploittir (n)."},{"q":"Mayoz II'de metafaz II evresinde kromozomlar nasıl dizilir?","steps":[{"t":"Metafaz II","a":"Dizilme evresi","d":"Metafaz II, kromozomların düzenlendiği evredir. Kromozomlar hücrenin belirli bir bölgesine gelir."},{"t":"Diziliş","a":"Ekvatorda tek sıra","d":"Kromozomlar hücrenin ekvator (orta) düzleminde tek sıra halinde dizilir. Bu mitoz metafazına benzer bir dizilimdir."}],"ans":"Metafaz II'de kromozomlar ekvator düzleminde tek sıra halinde dizilir."},{"q":"Mayoz II neden DNA eşlenmeden başlar?","steps":[{"t":"Mayoz I sonrası","a":"Hücreler yeni oluştu","d":"Mayoz I biter bitmez oluşan hücreler doğrudan Mayoz II'ye geçer. Araya DNA kopyalama aşaması girmez."},{"t":"Sonuç","a":"Madde azalır","d":"DNA eşlenmediği için her bölünmede kalıtsal madde azalmaya devam eder. Bu sayede haploid gametler oluşur."}],"ans":"Kromozom sayısının yarıya inmesini tamamlamak için Mayoz II DNA eşlenmeden başlar."}],"zor":[{"q":"Mayoz II'nin dört evresinde gerçekleşen temel olayları sırasıyla açıklayınız.","steps":[{"t":"Profaz II","a":"Kromozomlar belirginleşir","d":"Profaz II'de çekirdek zarı erir ve kromozomlar yeniden kısalıp kalınlaşır. İğ iplikleri oluşmaya başlar."},{"t":"Metafaz II","a":"Ekvatorda dizilim","d":"Metafaz II'de kromozomlar hücre ortasında tek sıra halinde dizilir. İğ iplikleri sentromerlere tutunur."},{"t":"Anafaz ve Telofaz II","a":"Ayrılma ve bölünme","d":"Anafaz II'de kardeş kromatitler zıt kutuplara çekilir, telofaz II'de ise hücre tamamen ikiye bölünür. Böylece dört evre tamamlanır."}],"ans":"Profaz II'de kromozom belirginleşir, metafaz II'de dizilir, anafaz II'de kardeş kromatitler ayrılır, telofaz II'de hücre bölünür."},{"q":"Mayoz I sonunda 2 haploid hücre varken Mayoz II sonunda neden 4 haploid hücre oluşur?","steps":[{"t":"Başlangıç durumu","a":"2 haploid (n) hücre","d":"Mayoz I sonunda kromozom sayısı yarıya inmiş 2 haploid hücre bulunur. Bunlar (n) kromozomludur."},{"t":"Mayoz II bölünmesi","a":"Her hücre ikiye","d":"Mayoz II'de bu 2 hücrenin her biri kardeş kromatitlerini ayırarak ikiye bölünür. DNA eşlenmediği için kromozom sayısı (n) kalır."},{"t":"Sonuç","a":"4 haploid hücre","d":"İki hücreden dördü oluşur ve hepsi haploittir. Mayoz sonunda toplam 4 (n) hücre meydana gelir."}],"ans":"2 haploid hücrenin her biri Mayoz II'de bölündüğü için 4 haploid (n) hücre oluşur."},{"q":"Mayoz II ile mitoz arasındaki benzerliği ve farkı açıklayınız.","steps":[{"t":"Benzerlik","a":"Kardeş kromatit ayrılması","d":"Mayoz II ve mitozda kardeş kromatitler anafazda birbirinden ayrılır. Bu nedenle olay akışı benzerdir."},{"t":"Başlangıç farkı","a":"n ve 2n","d":"Mitoz 2n diploid hücrede başlarken Mayoz II haploid (n) hücrede başlar. Başlangıç kromozom sayıları farklıdır."},{"t":"Sonuç farkı","a":"Madde durumu","d":"Mitoz sonunda 2n hücreler, Mayoz II sonunda ise n hücreler oluşur. Mayoz II'de DNA eşlenmesi yokken mitozdan önce DNA eşlenir."}],"ans":"Benzerlik kardeş kromatit ayrılmasıdır; fark ise Mayoz II'nin haploit hücrede ve DNA eşlenmesi olmadan başlamasıdır."},{"q":"Mayoz II'de telofaz II evresinde neler gerçekleşir?","steps":[{"t":"Kutuplara varış","a":"Kromatitler ulaşır","d":"Anafaz II'de ayrılan kardeş kromatitler hücre kutuplarına ulaşır. Artık her kutupta tam takım kromozom bulunur."},{"t":"Çekirdek oluşumu","a":"Zar yeniden oluşur","d":"Telofaz II'de kromozomların çevresinde yeniden çekirdek zarı oluşur. Kromozomlar gevşeyip uzun hale gelir."},{"t":"Sitoplazma bölünmesi","a":"4 hücre tamamlanır","d":"Sitoplazma bölünmesiyle hücre tamamen ikiye ayrılır. Mayoz sonunda toplam 4 haploid hücre ortaya çıkar."}],"ans":"Telofaz II'de çekirdek zarı yeniden oluşur, sitoplazma bölünür ve toplam 4 haploid hücre meydana gelir."},{"q":"Mayoz II'nin görevini ve sonucunu açıklayınız.","steps":[{"t":"Görev","a":"Bölünmeyi tamamlama","d":"Mayoz II'nin görevi Mayoz I'den gelen haploid hücreleri tekrar bölmektir. Böylece üreme hücrelerinin oluşumu tamamlanır."},{"t":"Olay","a":"Kromatit ayrılması","d":"Mayoz II'de kardeş kromatitler ayrılarak ayrı hücrelere dağılır. DNA eşlenmesi olmaz."},{"t":"Sonuç","a":"4 haploid gamet","d":"Sonuçta kromozom sayısı yarıya inmiş 4 haploid hücre oluşur. Bu hücreler gamet (üreme hücresi) olarak görev yapar."}],"ans":"Mayoz II haploid hücreleri tekrar bölerek toplam 4 haploid üreme hücresi oluşturur."}]},"lise":{"kolay":[{"q":"Mayoz II'nin evrelerini sırasıyla yazarak her birinde gerçekleşen temel olayı belirtiniz.","steps":[{"t":"Profaz II","a":"Kromozomlar yoğunlaşır","d":"Profaz II'de çekirdek zarı erir ve kromozomlar kısalıp kalınlaşarak belirginleşir. İğ iplikleri yeniden oluşmaya başlar."},{"t":"Metafaz II","a":"Ekvatorda dizilim","d":"Metafaz II'de kromozomlar hücrenin ekvator düzleminde tek sıra halinde dizilir. İğ iplikleri sentromerlere bağlanır."},{"t":"Anafaz ve Telofaz II","a":"Ayrılma ve bölünme","d":"Anafaz II'de kardeş kromatitler zıt kutuplara çekilir, telofaz II'de çekirdek zarı oluşur ve sitoplazma bölünür. Böylece 4 haploid hücre meydana gelir."}],"ans":"Profaz II, Metafaz II, Anafaz II ve Telofaz II; anafaz II'de kardeş kromatitler ayrılır."},{"q":"Mayoz II'ye giren hücrelerin haploid (n) olmasının nedeni nedir?","steps":[{"t":"Mayoz I etkisi","a":"Homologlar ayrıldı","d":"Mayoz I'de homolog kromozomlar birbirinden ayrılmış ve kromozom sayısı yarıya inmiştir. Oluşan hücreler haploit (n) hale gelmiştir."},{"t":"Mayoz II girişi","a":"n hücreler bölünür","d":"Bu haploid hücreler doğrudan Mayoz II'ye girer. Kromozom sayısı zaten (n) düzeyindedir."}],"ans":"Mayoz I'de homolog kromozomlar ayrıldığı için Mayoz II'ye giren hücreler haploittir (n)."},{"q":"Mayoz II'de neden DNA eşlenmesi (interfaz S evresi) görülmez?","steps":[{"t":"Mayoz I sonrası geçiş","a":"Doğrudan bölünme","d":"Mayoz I bittikten sonra hücreler genellikle kısa bir ara evreyle Mayoz II'ye geçer. Bu sürede DNA replikasyonu gerçekleşmez."},{"t":"Amaç","a":"Kromozom sayısını korumak","d":"Eğer DNA eşlenseydi kromozom sayısı yine ikiye katlanır ve haploid gamet oluşamazdı. Bu nedenle Mayoz II eşlenme olmadan ilerler."}],"ans":"Kromozom sayısının haploid kalmasını sağlamak için Mayoz II'de DNA eşlenmesi görülmez."},{"q":"Anafaz II ile mitoz anafazı arasındaki benzerlik nedir?","steps":[{"t":"Mitoz anafazı","a":"Kromatit ayrılması","d":"Mitoz anafazında her kromozomun kardeş kromatitleri sentromerden ayrılarak zıt kutuplara çekilir. Bu eşit paylaşımı sağlar."},{"t":"Anafaz II","a":"Aynı olay","d":"Anafaz II'de de kardeş kromatitler ayrılarak kutuplara gider. Bu olay mitoz anafazıyla aynıdır."}],"ans":"Her ikisinde de kardeş kromatitlerin sentromerden ayrılarak zıt kutuplara çekilmesi ortaktır."},{"q":"Bir hücre Mayoz I ve Mayoz II'yi tamamladığında kaç hücre ve hangi kromozom yapısında oluşur?","steps":[{"t":"Mayoz I sonucu","a":"2 haploid hücre","d":"Mayoz I sonunda 1 diploid hücreden 2 haploid (n) hücre oluşur. Homolog kromozomlar ayrılmıştır."},{"t":"Mayoz II sonucu","a":"4 haploid hücre","d":"Mayoz II'de bu 2 hücre bölünerek 4 haploid hücre verir. Tüm hücreler (n) kromozomludur."}],"ans":"Toplamda 4 haploid (n) hücre oluşur."},{"q":"Profaz II evresinde çekirdek zarı ve iğ iplikleriyle ilgili neler olur?","steps":[{"t":"Çekirdek zarı","a":"Erir","d":"Profaz II'de telofaz I sonunda oluşmuşsa çekirdek zarı yeniden erir. Kromozomlar serbest hale geçer."},{"t":"İğ iplikleri","a":"Yeniden oluşur","d":"Sentrozomlar kutuplara giderek iğ ipliklerinin oluşmasını sağlar. Bu iplikler kromozomları taşıyacaktır."}],"ans":"Profaz II'de çekirdek zarı erir ve iğ iplikleri yeniden oluşur."},{"q":"Metafaz II'de iğ iplikleri kromozomlara nereden tutunur?","steps":[{"t":"Tutunma bölgesi","a":"Sentromer","d":"İğ iplikleri kromozomların sentromer bölgesindeki kinetokorlara tutunur. Bu bağlantı kromozomları yönlendirir."},{"t":"Dizilim","a":"Ekvatorda tek sıra","d":"Tutunan kromozomlar ekvator düzleminde tek sıra halinde dizilir. Bu dizilim ayrılmadan önceki son aşamadır."}],"ans":"İğ iplikleri kromozomlara sentromer bölgesindeki kinetokorlardan tutunur."},{"q":"Mayoz II sonunda oluşan 4 hücrenin kromozom sayısı ana hücreye göre nasıldır?","steps":[{"t":"Ana hücre","a":"Diploid (2n)","d":"Mayoza giren ana hücre diploittir, yani kromozom takımı tamdır (2n). Bu hücre eşey ana hücresidir."},{"t":"Oluşan hücreler","a":"Haploid (n)","d":"Mayoz sonunda oluşan 4 hücre haploittir (n). Kromozom sayısı ana hücrenin yarısıdır."}],"ans":"Oluşan 4 hücrenin kromozom sayısı ana hücrenin (2n) yarısı kadar, yani haploittir (n)."},{"q":"Mayoz II, mitoza benzese de neden mitozdan farklı bir sonuç doğurur?","steps":[{"t":"Olay benzerliği","a":"Kromatit ayrılması","d":"Mayoz II'de mitozdaki gibi kardeş kromatitler ayrılır. Olay akışı benzer görünür."},{"t":"Başlangıç farkı","a":"Haploid hücre","d":"Mayoz II haploid (n) hücrede başlar, mitoz ise diploid (2n) hücrede başlar. Bu yüzden çıkan ürünler farklıdır."}],"ans":"Mayoz II haploid hücrede başladığı için sonuçta haploid hücreler verir, mitoz ise diploid hücreler verir."},{"q":"Telofaz II evresinde sitokinez (sitoplazma bölünmesi) ne işe yarar?","steps":[{"t":"Sitokinez","a":"Hücreyi ayırır","d":"Sitokinez, hücrenin sitoplazmasının ikiye bölünmesi olayıdır. Bu sayede iki ayrı hücre tam olarak oluşur."},{"t":"Sonuç","a":"4 ayrı hücre","d":"Her iki Mayoz II hücresinde sitokinez gerçekleştiğinde toplam 4 ayrı hücre meydana gelir. Mayoz tamamlanmış olur."}],"ans":"Sitokinez sitoplazmayı bölerek toplam 4 ayrı haploid hücrenin oluşmasını sağlar."},{"q":"Mayoz I ile Mayoz II arasında DNA miktarı bakımından temel fark nedir?","steps":[{"t":"Mayoz I öncesi","a":"DNA eşlenmiş","d":"Mayoz I'den önce interfazda DNA eşlenir ve her kromozom iki kardeş kromatitten oluşur. DNA miktarı yüksektir."},{"t":"Mayoz II öncesi","a":"DNA eşlenmez","d":"Mayoz II'den önce DNA tekrar eşlenmez. Hücre var olan kromatitlerle bölünmeye girer."}],"ans":"Mayoz I öncesinde DNA eşlenir, Mayoz II öncesinde ise DNA eşlenmez."},{"q":"Mayoz II sonunda erkekte ve genel olarak oluşan hücrelere ne ad verilir?","steps":[{"t":"Oluşan hücreler","a":"Haploid hücreler","d":"Mayoz II sonunda kromozom sayısı yarıya inmiş 4 haploid hücre oluşur. Bunlar üreme için özelleşir."},{"t":"Genel ad","a":"Gamet","d":"Bu haploid üreme hücrelerine genel olarak gamet denir. Erkekte bunlar olgunlaşarak sperm oluşturur."}],"ans":"Mayoz II sonunda oluşan haploid üreme hücrelerine gamet denir."},{"q":"Metafaz II ile metafaz I arasındaki dizilim farkı nedir?","steps":[{"t":"Metafaz I","a":"İkili dizilim","d":"Metafaz I'de homolog kromozomlar çift (tetrat) halinde ekvatorda karşılıklı dizilir. Diziliş ikili gruplar şeklindedir."},{"t":"Metafaz II","a":"Tekli dizilim","d":"Metafaz II'de kromozomlar tek tek ekvator düzleminde sıralanır. Mitoz metafazına benzer bir tekli dizilim görülür."}],"ans":"Metafaz I'de homologlar çift halinde, metafaz II'de ise kromozomlar tek sıra halinde dizilir."},{"q":"Mayoz II evresinin gerçekleşmesi neden mayozun tamamlanması için gereklidir?","steps":[{"t":"Mayoz I yetersizliği","a":"2 hücre, henüz tamamlanmadı","d":"Mayoz I sonunda yalnızca 2 haploid hücre oluşur ve kardeş kromatitler hâlâ birliktedir. Bölünme henüz bitmemiştir."},{"t":"Mayoz II gereği","a":"Kromatitler ayrılır","d":"Mayoz II ile kardeş kromatitler ayrılır ve hücre sayısı 4'e çıkar. Böylece gerçek gametler oluşur."}],"ans":"Kardeş kromatitlerin ayrılıp 4 gamet oluşması için Mayoz II gereklidir."},{"q":"Anafaz II'de kardeş kromatitler ayrıldığında her kutba ne gider?","steps":[{"t":"Ayrılma","a":"Sentromer bölünür","d":"Anafaz II'de sentromerler bölünür ve kardeş kromatitler birbirinden ayrılır. Her kromatit artık bağımsız bir kromozom olur."},{"t":"Kutuplara gidiş","a":"Tek takım kromozom","d":"Ayrılan kromozomlar zıt kutuplara çekilir. Her kutba haploid bir kromozom takımı ulaşır."}],"ans":"Anafaz II'de her kutba kardeş kromatitlerden gelen haploid bir kromozom takımı gider."}],"zor":[{"q":"2n=8 kromozomlu bir eşey ana hücresinin Mayoz II sonunda oluşturduğu hücre sayısını ve kromozom sayısını adım adım hesaplayınız.","steps":[{"t":"Mayoz I sonucu","a":"2 hücre, n=4","d":"2n=8 olan hücre Mayoz I'de homolog kromozomları ayırarak 2 haploid hücre oluşturur. Her hücrede n=4 kromozom bulunur."},{"t":"Mayoz II bölünmesi","a":"Her hücre ikiye","d":"Mayoz II'de bu 2 hücrenin her biri DNA eşlenmeden bölünür. Kromozom sayısı n=4 olarak korunur."},{"t":"Sonuç","a":"4 hücre, n=4","d":"Mayoz sonunda toplam 4 hücre oluşur ve her birinde 4 kromozom bulunur. Hepsi haploittir."}],"ans":"Toplam 4 hücre oluşur ve her birinde n=4 kromozom bulunur."},{"q":"Mayoz II'de DNA eşlenmesi gerçekleşseydi gametlerin kromozom sayısı nasıl etkilenirdi? Açıklayınız.","steps":[{"t":"Normal durum","a":"n haploid gamet","d":"Normalde Mayoz II DNA eşlenmeden gerçekleşir ve haploid (n) gametler oluşur. Bu döllenmede 2n'in korunmasını sağlar."},{"t":"Eşlenme olsaydı","a":"Kromatit sayısı artardı","d":"DNA eşlenseydi her kromozom yeniden iki kardeş kromatit oluşturur ve bölünme sonunda kromozom sayısı yarıya inmezdi. Gametler haploit olamazdı."},{"t":"Sonuç","a":"2n korunamazdı","d":"Böyle gametler döllenince zigotun kromozom sayısı sürekli artar ve türün kromozom sayısı korunamazdı. Bu nedenle eşlenme görülmez."}],"ans":"DNA eşlenseydi gametler haploit olamaz, döllenmeyle kromozom sayısı sürekli artar ve türün 2n sayısı korunamazdı."},{"q":"Mayoz II'nin dört evresinde kromozom ve sentromer davranışını ayrıntılı açıklayınız.","steps":[{"t":"Profaz II","a":"Kromozomlar yoğunlaşır","d":"Profaz II'de çekirdek zarı erir, kromozomlar kısalıp kalınlaşır ve iğ iplikleri oluşur. Her kromozom hâlâ iki kardeş kromatit ve ortak bir sentromer içerir."},{"t":"Metafaz II","a":"Sentromer ekvatorda","d":"Metafaz II'de kromozomlar sentromerlerinden iğ ipliklerine tutunarak ekvator düzleminde dizilir. Kardeş kromatitler hâlâ birlikte durur."},{"t":"Anafaz-Telofaz II","a":"Sentromer bölünür","d":"Anafaz II'de sentromerler bölünür ve kardeş kromatitler zıt kutuplara çekilir. Telofaz II'de çekirdek zarları oluşur ve sitokinezle 4 haploid hücre tamamlanır."}],"ans":"Profaz II'de kromozomlar yoğunlaşır, metafaz II'de sentromerlerden dizilir, anafaz II'de sentromer bölünüp kardeş kromatitler ayrılır, telofaz II'de hücreler bölünür."},{"q":"Mayoz II'nin mitozla benzer olmasına rağmen genetik açıdan farklı hücreler vermesinin nedenini açıklayınız.","steps":[{"t":"Olay benzerliği","a":"Kromatit ayrılması","d":"Mayoz II'de mitozdaki gibi kardeş kromatitler ayrılır. Mekanik olarak iki bölünme benzer ilerler."},{"t":"Önceki olaylar","a":"Krossing-over etkisi","d":"Mayoz I'de gerçekleşen krossing-over sonucu kardeş kromatitler artık genetik olarak birbirinin tıpatıp aynısı değildir. Bu farklılık Mayoz II hücrelerine yansır."},{"t":"Sonuç","a":"Genetik çeşitlilik","d":"Krossing-over ve bağımsız dağılım nedeniyle oluşan 4 hücre genetik olarak farklı olabilir. Mitozda ise oluşan hücreler özdeştir."}],"ans":"Mayoz I'deki krossing-over nedeniyle kardeş kromatitler farklılaştığı için, mitoza benzese de Mayoz II genetik olarak farklı hücreler verir."},{"q":"Telofaz I ile telofaz II arasındaki kromozom sayısı ve DNA durumu farkını açıklayınız.","steps":[{"t":"Telofaz I","a":"n, kromatitli","d":"Telofaz I sonunda haploid (n) hücreler oluşur ancak her kromozom hâlâ iki kardeş kromatit içerir. Kromozom sayısı yarıya inmiş, DNA miktarı henüz fazladır."},{"t":"Telofaz II","a":"n, tek kromatitli","d":"Telofaz II sonunda yine haploid (n) hücreler oluşur ama her kromozom tek kromatitlidir. DNA miktarı da yarıya inmiştir."},{"t":"Karşılaştırma","a":"DNA yarıya iner","d":"Kromozom sayısı her iki telofazda da n'dir; fark kromatit sayısı ve DNA miktarındadır. Telofaz II'de hücre tam olgunlaşmış gamet yapısına ulaşır."}],"ans":"Her ikisinde de kromozom sayısı n'dir; ancak telofaz I'de kromozomlar çift kromatitli, telofaz II'de tek kromatitlidir ve DNA miktarı yarıya inmiştir."},{"q":"Mayoz II'de iğ ipliklerinin görevini ve bozulması durumunda oluşabilecek sonucu açıklayınız.","steps":[{"t":"İğ ipliği görevi","a":"Kromatitleri çeker","d":"İğ iplikleri sentromerlere tutunarak anafaz II'de kardeş kromatitleri zıt kutuplara çeker. Bu sayede eşit dağılım sağlanır."},{"t":"Bozulma durumu","a":"Ayrılma olmaz","d":"İğ iplikleri bozulursa kromatitler düzgün ayrılamaz. Kromozomlar hücreler arasında dengesiz dağılır."},{"t":"Sonuç","a":"Anöploidi","d":"Bu durumda bazı gametlerde fazla, bazılarında eksik kromozom bulunur (anöploidi). Bu kromozom sayısı hastalıklarına yol açabilir."}],"ans":"İğ iplikleri kardeş kromatitleri eşit ayırır; bozulursa kromozomlar dengesiz dağılır ve anöploidi oluşur."},{"q":"Bir bitki hücresinde Mayoz II'nin sitokinezi hayvan hücresinden nasıl farklılaşır?","steps":[{"t":"Hayvan hücresinde","a":"Boğumlanma","d":"Hayvan hücresinde sitokinez, hücre zarının içe doğru boğumlanmasıyla gerçekleşir. Hücre ortadan sıkışarak ikiye ayrılır."},{"t":"Bitki hücresinde","a":"Orta lamel","d":"Bitki hücresinde hücre çeperi bulunduğu için boğumlanma olmaz. Ortada hücre plağı (orta lamel) oluşarak hücreyi ikiye böler."},{"t":"Sonuç","a":"Aynı amaç","d":"Her iki yöntem de sonuçta sitoplazmayı bölerek iki ayrı haploid hücre oluşturur. Mekanizma farklı, sonuç aynıdır."}],"ans":"Hayvan hücresinde boğumlanmayla, bitki hücresinde ise orta lamel (hücre plağı) oluşumuyla sitokinez gerçekleşir."},{"q":"2n=4 kromozomlu bir hücrede Mayoz II metafazındaki bir hücrede kaç kromozom ve kaç kromatit bulunur? Açıklayınız.","steps":[{"t":"Mayoz II hücresi","a":"Haploid n=2","d":"2n=4 olan hücre Mayoz I sonunda n=2 kromozomlu haploid hücreler verir. Mayoz II metafazındaki hücre bu haploid yapıdadır."},{"t":"Kromatit durumu","a":"Hâlâ çift kromatitli","d":"Mayoz II metafazında kardeş kromatitler henüz ayrılmamıştır. Her kromozom 2 kardeş kromatit içerir."},{"t":"Hesap","a":"2 kromozom, 4 kromatit","d":"Hücrede 2 kromozom bulunur ve her biri 2 kromatitli olduğu için toplam 4 kromatit vardır. Anafaz II'de bunlar ayrılacaktır."}],"ans":"Mayoz II metafazındaki hücrede 2 kromozom ve toplam 4 kromatit bulunur."},{"q":"Mayoz II sırasında bir hücrede anafaz II ayrımı düzgün olmazsa (ayrılmama / nondisjunction) gametler nasıl etkilenir?","steps":[{"t":"Normal ayrılma","a":"Eşit dağılım","d":"Normalde anafaz II'de kardeş kromatitler eşit şekilde iki kutba ayrılır. Her gamet doğru sayıda kromozom alır."},{"t":"Ayrılmama","a":"Dengesiz dağılım","d":"Ayrılmama olursa iki kardeş kromatit aynı kutba gider. Bir gamet fazla kromozom alırken diğeri eksik kalır."},{"t":"Sonuç","a":"n+1 ve n-1","d":"Sonuçta bazı gametler n+1, bazıları n-1 kromozomlu olur. Bu gametlerin döllenmesi kromozom sayısı bozukluklarına yol açar."}],"ans":"Anafaz II'de ayrılmama olursa bir gamet fazla (n+1), diğeri eksik (n-1) kromozomlu olur ve kromozom sayısı bozuklukları oluşabilir."},{"q":"Mayoz I ile Mayoz II arasındaki kısa evreye (interkinez) neden DNA replikasyonu girmez? Genetik sonucu nasıldır?","steps":[{"t":"İnterkinez","a":"Kısa ara evre","d":"Mayoz I ile Mayoz II arasındaki kısa dinlenme evresine interkinez denir. Bu evre normal interfazdan farklıdır."},{"t":"Replikasyon yokluğu","a":"DNA eşlenmez","d":"İnterkinezde DNA replikasyonu (S evresi) gerçekleşmez. Hücre var olan kromatitleriyle Mayoz II'ye girer."},{"t":"Genetik sonuç","a":"Kromozom sayısı korunur","d":"Replikasyon olmadığı için Mayoz II sonunda kromozom sayısı haploid kalır. Böylece dört haploid gamet doğru şekilde oluşur."}],"ans":"İnterkinezde DNA eşlenmez; bu sayede Mayoz II sonunda kromozom sayısı haploid kalır ve dört haploid gamet oluşur."},{"q":"Spermatogenezde Mayoz II sonunda kaç hücre oluşur ve bunlar hangi adı alır? Açıklayınız.","steps":[{"t":"Mayoz I sonucu","a":"2 ikincil spermatosit","d":"Spermatogenezde birincil spermatosit Mayoz I geçirir ve 2 ikincil spermatosit oluşur. Bunlar haploittir."},{"t":"Mayoz II sonucu","a":"4 spermatit","d":"Her ikincil spermatosit Mayoz II geçirerek toplam 4 spermatit oluşturur. Spermatitler haploit hücrelerdir."},{"t":"Olgunlaşma","a":"4 sperm","d":"Spermatitler olgunlaşarak işlevsel sperm hücrelerine dönüşür. Sonuçta bir birincil spermatositten 4 sperm oluşur."}],"ans":"Mayoz II sonunda 4 spermatit oluşur ve bunlar olgunlaşarak 4 sperm hücresini verir."},{"q":"Oogenezde Mayoz II'nin sonucu spermatogenezden nasıl farklıdır? Açıklayınız.","steps":[{"t":"Spermatogenez","a":"4 işlevsel gamet","d":"Spermatogenezde Mayoz II sonunda eşit sitoplazma paylaşımıyla 4 işlevsel sperm oluşur. Hepsi döllenebilir."},{"t":"Oogenez","a":"Eşitsiz bölünme","d":"Oogenezde sitoplazma eşit paylaşılmaz. Mayoz II sonunda 1 büyük yumurta (ovum) ve küçük kutup cisimcikleri oluşur."},{"t":"Sonuç","a":"1 yumurta","d":"Sadece 1 hücre bol sitoplazmalı işlevsel yumurta olur, diğerleri kutup cisimciği olarak körelir. Bu, yumurtaya besin yedeği sağlar."}],"ans":"Spermatogenezde 4 işlevsel gamet oluşurken, oogenezde Mayoz II sonunda yalnızca 1 işlevsel yumurta ve körelen kutup cisimcikleri oluşur."},{"q":"Mayoz II metafazında kromozomların dizilimi mitoz metafazına benzer ama gerçekleştiği hücre farklıdır. Bunu açıklayınız.","steps":[{"t":"Dizilim benzerliği","a":"Tek sıra ekvatorda","d":"Mayoz II metafazında ve mitoz metafazında kromozomlar ekvatorda tek sıra halinde dizilir. Diziliş şekli benzerdir."},{"t":"Hücre farkı","a":"n ve 2n","d":"Mitoz metafazı diploid (2n) hücrede gerçekleşirken Mayoz II metafazı haploid (n) hücrede gerçekleşir. Kromozom sayıları farklıdır."},{"t":"Sonuç farkı","a":"Ürün farkı","d":"Mitoz sonunda 2n hücreler, Mayoz II sonunda n hücreler oluşur. Aynı görünen dizilim farklı sonuçlar doğurur."}],"ans":"Diziliş tek sıra olarak benzer; ancak mitoz metafazı 2n hücrede, Mayoz II metafazı n hücrede gerçekleştiği için sonuçlar farklıdır."},{"q":"Mayoz II tamamlandığında bir hücredeki DNA miktarı, mayozun başındaki diploid hücreye göre nasıl değişir? Nicel olarak açıklayınız.","steps":[{"t":"Başlangıç","a":"2C'den 4C'ye","d":"Mayoz öncesi interfazda DNA eşlenir ve diploid hücrenin DNA miktarı 2C'den 4C'ye çıkar. Her kromozom çift kromatitlidir."},{"t":"Mayoz I sonrası","a":"2C","d":"Mayoz I'de homologlar ayrıldığında DNA miktarı 4C'den 2C'ye düşer. Hücreler haploid olur ama kromatitler hâlâ çifttir."},{"t":"Mayoz II sonrası","a":"1C","d":"Mayoz II'de kardeş kromatitler ayrılınca DNA miktarı 2C'den 1C'ye iner. Sonuçta her gametin DNA miktarı başlangıçtaki haploid değerin (1C) düzeyindedir."}],"ans":"Eşlenmiş diploid hücrenin DNA miktarı 4C iken, Mayoz II sonunda her gamette DNA miktarı 1C'ye, yani dörtte birine iner."},{"q":"Mayoz II'nin gerçekleşmemesi (yalnızca Mayoz I olması) durumunda oluşan hücrelerin yapısını ve döllenmedeki etkisini açıklayınız.","steps":[{"t":"Yalnız Mayoz I","a":"2 hücre, çift kromatitli","d":"Sadece Mayoz I gerçekleşirse 2 haploid hücre oluşur ama her kromozom hâlâ iki kardeş kromatit içerir. Bölünme yarıda kalmış olur."},{"t":"Sorun","a":"Kromatitler ayrılmamış","d":"Kardeş kromatitler ayrılmadığı için bu hücreler tam olgun gamet değildir. DNA miktarı normalin iki katı (2C) kalır."},{"t":"Döllenme etkisi","a":"Kromozom dengesizliği","d":"Bu hücreler döllenmede kullanılırsa zigotun kromozom ve DNA dengesi bozulur. Bu nedenle Mayoz II tamamlanmalıdır."}],"ans":"Mayoz II olmazsa kardeş kromatitleri ayrılmamış, DNA miktarı fazla (2C) hücreler oluşur; bunların döllenmesi kromozom dengesizliğine yol açar."}]}},"mitozMayozKarsi":{"ilkokul":{"kolay":[{"q":"Mitoz bölünmede kaç hücre, mayoz bölünmede kaç hücre oluşur?","steps":[{"t":"Mitoz","a":"2 hücre","d":"Mitoz bölünme sonucunda bir hücreden 2 yeni hücre oluşur. Bu hücreler birbirine benzer."},{"t":"Mayoz","a":"4 hücre","d":"Mayoz bölünme sonucunda bir hücreden 4 yeni hücre oluşur. Bu hücreler üreme için kullanılır."}],"ans":"Mitozda 2, mayozda 4 hücre oluşur."},{"q":"Mitoz bölünme kaç bölünme, mayoz bölünme kaç bölünmeden oluşur?","steps":[{"t":"Mitoz","a":"1 bölünme","d":"Mitoz tek bir bölünmeden oluşur. Hücre bir kez bölünür."},{"t":"Mayoz","a":"2 bölünme","d":"Mayoz iki ardışık bölünmeden oluşur. Hücre üst üste iki kez bölünür."}],"ans":"Mitoz 1, mayoz 2 bölünmeden oluşur."},{"q":"Mitoz vücut hücrelerinde mi yoksa üreme hücrelerinde mi olur?","steps":[{"t":"Mitoz yeri","a":"Vücut hücreleri","d":"Mitoz bölünme vücut hücrelerinde gerçekleşir. Bu hücreler büyüme ve onarımı sağlar."},{"t":"Görev","a":"Büyüme ve onarım","d":"Mitoz sayesinde vücudumuz büyür ve yaralarımız iyileşir. Yeni hücreler eskilerin yerini alır."}],"ans":"Mitoz vücut hücrelerinde olur."},{"q":"Mayoz bölünme hangi hücrelerde gerçekleşir?","steps":[{"t":"Mayoz yeri","a":"Üreme hücreleri","d":"Mayoz bölünme eşey (üreme) ana hücrelerinde gerçekleşir. Bu hücreler gamet oluşturur."},{"t":"Görev","a":"Gamet oluşturma","d":"Mayoz sayesinde sperm ve yumurta gibi üreme hücreleri oluşur. Bu hücreler yeni canlının oluşmasını sağlar."}],"ans":"Mayoz üreme (eşey ana) hücrelerinde gerçekleşir."},{"q":"Mitozla oluşan hücreler birbirine benzer mi, mayozla oluşanlar benzer mi?","steps":[{"t":"Mitoz hücreleri","a":"Birbirine benzer","d":"Mitozla oluşan hücreler ana hücreye ve birbirine benzer. Kalıtsal özellikleri aynıdır."},{"t":"Mayoz hücreleri","a":"Birbirinden farklı","d":"Mayozla oluşan hücreler birbirinden ve ana hücreden farklı olabilir. Bu farklılık çeşitliliği sağlar."}],"ans":"Mitozla oluşan hücreler birbirine benzer, mayozla oluşanlar farklı olabilir."}],"zor":[{"q":"Mitoz ve mayoz bölünmenin oluşturduğu hücre sayısı neden farklıdır? Açıklayınız.","steps":[{"t":"Mitozda bölünme","a":"1 kez bölünür","d":"Mitozda hücre yalnızca bir kez bölünür. Bu yüzden 1 hücreden 2 hücre oluşur."},{"t":"Mayozda bölünme","a":"2 kez bölünür","d":"Mayozda hücre iki kez üst üste bölünür. Bu yüzden 1 hücreden 4 hücre oluşur."},{"t":"Sonuç","a":"2'ye karşı 4","d":"Bölünme sayısı farklı olduğu için oluşan hücre sayısı da farklıdır. Mitozda 2, mayozda 4 hücre meydana gelir."}],"ans":"Mitoz 1 kez, mayoz 2 kez bölündüğü için mitozda 2, mayozda 4 hücre oluşur."},{"q":"Bir yaramız iyileşirken hangi bölünme çalışır ve neden? Açıklayınız.","steps":[{"t":"Yara iyileşmesi","a":"Yeni hücreler gerekir","d":"Yaramız iyileşirken yeni vücut hücrelerine ihtiyaç duyulur. Eksik hücrelerin yerini yenileri almalıdır."},{"t":"Bölünme türü","a":"Mitoz","d":"Vücut hücrelerinin çoğalması mitozla olur. Mitoz büyüme ve onarımdan sorumludur."},{"t":"Sonuç","a":"Mitoz iyileştirir","d":"Mitoz bölünme yeni hücreler üreterek yaranın kapanmasını sağlar. Bu yüzden iyileşmede mitoz çalışır."}],"ans":"Yara iyileşirken mitoz çalışır, çünkü mitoz büyüme ve onarım için yeni vücut hücreleri üretir."},{"q":"Bir canlının yumurta ve sperm hücreleri hangi bölünmeyle oluşur ve neden mayoz olmalıdır?","steps":[{"t":"Üreme hücreleri","a":"Yumurta ve sperm","d":"Canlının üremesi için yumurta ve sperm gibi gametler gerekir. Bu hücreler özeldir."},{"t":"Bölünme türü","a":"Mayoz","d":"Gametler mayoz bölünmeyle oluşur. Mayoz kalıtsal maddeyi yarıya indirir."},{"t":"Neden mayoz","a":"Madde yarıya iner","d":"Mayoz sayesinde gametlerin kalıtsal maddesi yarıya iner. Döllenmeyle iki gamet birleşince madde tekrar tamamlanır."}],"ans":"Yumurta ve sperm mayozla oluşur; çünkü mayoz kalıtsal maddeyi yarıya indirerek döllenmede dengeyi sağlar."},{"q":"Mitozla oluşan hücreler ana hücreye benzerken mayozla oluşanlar neden farklı olabilir?","steps":[{"t":"Mitoz","a":"Aynı kopya","d":"Mitozda kalıtsal madde olduğu gibi kopyalanır ve paylaşılır. Bu yüzden hücreler ana hücreyle aynıdır."},{"t":"Mayoz","a":"Karışım olur","d":"Mayozda kalıtsal maddenin yarısı paylaşılır ve karışım oluşur. Bu yüzden hücreler farklılaşır."},{"t":"Sonuç","a":"Benzer ve farklı","d":"Mitoz benzer hücreler, mayoz ise farklı hücreler oluşturur. Bu fark canlılarda çeşitlilik sağlar."}],"ans":"Mitozda madde aynen kopyalandığı için hücreler benzer, mayozda madde karışıp yarıya indiği için hücreler farklı olabilir."},{"q":"Tek hücreli bir canlı eşeysiz çoğalırken mitozdan nasıl yararlanır? Açıklayınız.","steps":[{"t":"Eşeysiz üreme","a":"Tek canlı çoğalır","d":"Bazı canlılar eş bulmadan tek başına çoğalabilir. Buna eşeysiz üreme denir."},{"t":"Bölünme türü","a":"Mitoz","d":"Eşeysiz üremede mitoz bölünme kullanılır. Canlı kendine benzer yeni bireyler oluşturur."},{"t":"Sonuç","a":"Aynı bireyler","d":"Mitozla oluşan yeni bireyler ana canlıyla aynıdır. Böylece tür hızla çoğalabilir."}],"ans":"Tek hücreli canlı eşeysiz üremede mitozla bölünür ve kendine tıpatıp benzeyen yeni bireyler oluşturur."}]},"ortaokul":{"kolay":[{"q":"Mitoz ve mayozun gerçekleştiği yerleri karşılaştırınız.","steps":[{"t":"Mitoz yeri","a":"Vücut hücreleri","d":"Mitoz bölünme vücut (soma) hücrelerinde gerçekleşir. Büyüme ve onarımı sağlar."},{"t":"Mayoz yeri","a":"Eşey ana hücreleri","d":"Mayoz bölünme eşey ana hücrelerinde gerçekleşir. Bu hücreler gamet oluşturur."}],"ans":"Mitoz vücut hücrelerinde, mayoz ise eşey ana hücrelerinde gerçekleşir."},{"q":"Mitoz ve mayoz sonucu oluşan hücrelerin kromozom sayısını karşılaştırınız.","steps":[{"t":"Mitoz sonucu","a":"2n korunur","d":"Mitozda oluşan hücrelerin kromozom sayısı ana hücreyle aynıdır (2n). Diploid yapı korunur."},{"t":"Mayoz sonucu","a":"n'e iner","d":"Mayozda oluşan hücrelerin kromozom sayısı yarıya iner (n). Haploid hücreler oluşur."}],"ans":"Mitozda kromozom sayısı 2n korunur, mayozda ise yarıya inerek n olur."},{"q":"Krossing-over olayı mitozda mı mayozda mı görülür?","steps":[{"t":"Krossing-over","a":"Parça değişimi","d":"Krossing-over, homolog kromozomlar arasında parça değişimidir. Genetik çeşitlilik sağlar."},{"t":"Görüldüğü bölünme","a":"Mayozda (profaz I)","d":"Krossing-over yalnızca mayoz bölünmenin profaz I evresinde görülür. Mitozda gerçekleşmez."}],"ans":"Krossing-over yalnızca mayozda (profaz I) görülür, mitozda görülmez."},{"q":"Mitoz ve mayozun bölünme sayısını karşılaştırınız.","steps":[{"t":"Mitoz","a":"1 bölünme","d":"Mitoz tek bir bölünme evresinden oluşur. Hücre bir kez bölünür."},{"t":"Mayoz","a":"2 bölünme","d":"Mayoz iki ardışık bölünmeden oluşur (Mayoz I ve Mayoz II). Hücre üst üste iki kez bölünür."}],"ans":"Mitoz 1, mayoz 2 bölünmeden oluşur."},{"q":"Mitoz ve mayozun görevlerini karşılaştırınız.","steps":[{"t":"Mitoz görevi","a":"Büyüme-onarım","d":"Mitoz büyüme, gelişme, yıpranan hücrelerin onarımı ve eşeysiz üremeyi sağlar. Vücut sürekliliğini korur."},{"t":"Mayoz görevi","a":"Gamet oluşturma","d":"Mayoz üreme hücrelerini (gamet) oluşturur. Eşeyli üremeyi mümkün kılar."}],"ans":"Mitoz büyüme-onarım-eşeysiz üreme sağlar, mayoz gamet oluşturur."}],"zor":[{"q":"Mitoz ve mayozun bölünme sayısı, hücre sayısı ve kromozom sayısı bakımından farklarını açıklayınız.","steps":[{"t":"Bölünme sayısı","a":"1'e karşı 2","d":"Mitoz 1 bölünme, mayoz ise 2 ardışık bölünmeden oluşur. Bu temel farktır."},{"t":"Hücre sayısı","a":"2'ye karşı 4","d":"Mitoz 2 hücre, mayoz 4 hücre oluşturur. Bölünme sayısı arttıkça hücre sayısı da artar."},{"t":"Kromozom sayısı","a":"2n'e karşı n","d":"Mitozda kromozom sayısı 2n korunur, mayozda ise n'e iner. Mayoz haploid hücreler verir."}],"ans":"Mitoz 1 bölünme-2 hücre-2n; mayoz 2 bölünme-4 hücre-n özelliği gösterir."},{"q":"Mitoz ve mayozun genetik sonuçlarını karşılaştırarak çeşitlilikle ilişkisini açıklayınız.","steps":[{"t":"Mitoz sonucu","a":"Özdeş hücreler","d":"Mitozda oluşan hücreler ana hücreyle genetik olarak özdeştir. Kalıtsal madde aynen kopyalanır."},{"t":"Mayoz sonucu","a":"Farklı hücreler","d":"Mayozda krossing-over ve bağımsız dağılım sayesinde farklı (çeşitli) hücreler oluşur. Genetik çeşitlilik artar."},{"t":"Çeşitlilik","a":"Mayoz sağlar","d":"Bu nedenle tür içi genetik çeşitliliği mayoz sağlar. Mitoz çeşitlilik oluşturmaz."}],"ans":"Mitoz özdeş hücreler verirken mayoz çeşitli hücreler verir; genetik çeşitliliği mayoz sağlar."},{"q":"Krossing-overün mitozda görülmemesi, mayozda görülmesinin genetik sonucu nedir? Açıklayınız.","steps":[{"t":"Mitoz","a":"Krossing-over yok","d":"Mitozda homolog kromozomlar yan yana gelmez ve krossing-over olmaz. Gen dizilimi korunur."},{"t":"Mayoz","a":"Krossing-over var","d":"Mayozda profaz I'de homolog kromozomlar arasında parça değişimi (krossing-over) olur. Genler yeniden düzenlenir."},{"t":"Sonuç","a":"Çeşitlilik farkı","d":"Bu yüzden mitoz özdeş hücreler verirken mayoz genetik olarak farklı gametler verir. Krossing-over çeşitliliğin temel kaynağıdır."}],"ans":"Krossing-over mitozda olmadığı için hücreler özdeş, mayozda olduğu için gametler genetik olarak farklı olur."},{"q":"Mitoz ve mayozun gerçekleştiği hücreler ve görevlerini bir bütün olarak karşılaştırınız.","steps":[{"t":"Mitoz","a":"Vücut hücresi-onarım","d":"Mitoz vücut hücrelerinde gerçekleşir ve büyüme, onarım ile eşeysiz üremeyi sağlar. Kromozom sayısı korunur."},{"t":"Mayoz","a":"Eşey hücresi-gamet","d":"Mayoz eşey ana hücrelerinde gerçekleşir ve gamet oluşturur. Kromozom sayısını yarıya indirir."},{"t":"Bütünsel fark","a":"Süreklilik ve üreme","d":"Mitoz bireyin sürekliliğini, mayoz ise türün eşeyli üremesini sağlar. İki bölünme farklı amaçlara hizmet eder."}],"ans":"Mitoz vücut hücrelerinde büyüme-onarım sağlar, mayoz eşey hücrelerinde gamet oluşturarak eşeyli üremeyi sağlar."},{"q":"Mayoz olmadan sadece mitozla üreyen bir türde kromozom sayısı nasıl korunurdu? Açıklayınız.","steps":[{"t":"Mitozun özelliği","a":"2n korunur","d":"Mitoz kromozom sayısını değiştirmez, 2n korunur. Gametler de mitozla oluşsaydı 2n olurdu."},{"t":"Döllenme sorunu","a":"Sayı katlanırdı","d":"İki 2n gamet döllenmeyle birleşseydi yavrunun kromozom sayısı 4n olurdu. Her nesilde sayı ikiye katlanırdı."},{"t":"Sonuç","a":"Mayoz gerekli","d":"Bu yüzden kromozom sayısının korunması için mayoz gereklidir. Mayoz gametleri n yaparak döllenmede 2n'i sağlar."}],"ans":"Sadece mitoz olsaydı her döllenmede kromozom sayısı katlanırdı; sayının korunması için mayoz gereklidir."}]},"lise":{"kolay":[{"q":"Mitoz ve mayozun bölünme sayısı ile sonuçta oluşan hücre sayısını karşılaştırınız.","steps":[{"t":"Bölünme sayısı","a":"1'e karşı 2","d":"Mitoz tek bölünmeden, mayoz iki ardışık bölünmeden (Mayoz I ve II) oluşur. Mayozda iki kez bölünme görülür."},{"t":"Hücre sayısı","a":"2'ye karşı 4","d":"Mitoz sonunda 2, mayoz sonunda 4 hücre oluşur. Bölünme sayısındaki fark hücre sayısına yansır."}],"ans":"Mitoz 1 bölünmeyle 2 hücre, mayoz 2 bölünmeyle 4 hücre oluşturur."},{"q":"Mitoz ve mayoz sonucu oluşan hücrelerin kromozom sayısını (2n / n) karşılaştırınız.","steps":[{"t":"Mitoz","a":"2n diploid","d":"Mitoz sonunda oluşan hücreler ana hücreyle aynı kromozom sayısına sahiptir (2n). Diploid yapı korunur."},{"t":"Mayoz","a":"n haploid","d":"Mayoz sonunda kromozom sayısı yarıya iner ve haploid (n) hücreler oluşur. Bu gametler için gereklidir."}],"ans":"Mitozda hücreler diploid (2n), mayozda ise haploid (n) olur."},{"q":"Krossing-overün mitoz ve mayozdaki durumunu karşılaştırınız.","steps":[{"t":"Mitoz","a":"Görülmez","d":"Mitozda homolog kromozomlar yan yana dizilmez (sinapsis olmaz), bu nedenle krossing-over görülmez. Genetik dizilim korunur."},{"t":"Mayoz","a":"Profaz I'de görülür","d":"Mayozda profaz I sırasında homolog kromozomlar eşleşir ve krossing-over gerçekleşir. Bu genetik çeşitlilik sağlar."}],"ans":"Krossing-over mitozda görülmez, mayozda ise profaz I'de görülür."},{"q":"Mitoz ve mayozun gerçekleştiği hücre tipini karşılaştırınız.","steps":[{"t":"Mitoz","a":"Vücut (soma) hücreleri","d":"Mitoz, çok hücreli canlıların vücut hücrelerinde gerçekleşir. Bu hücreler büyüme ve onarımı sağlar."},{"t":"Mayoz","a":"Eşey ana hücreleri","d":"Mayoz, eşey ana (üreme) hücrelerinde gerçekleşir. Bu hücreler gamet oluşturur."}],"ans":"Mitoz vücut hücrelerinde, mayoz eşey ana hücrelerinde gerçekleşir."},{"q":"Mitoz ve mayozun genetik sonucunu (özdeş / çeşitli) karşılaştırınız.","steps":[{"t":"Mitoz","a":"Özdeş hücreler","d":"Mitoz sonunda oluşan hücreler ana hücreyle ve birbiriyle genetik olarak özdeştir. Kalıtsal madde aynen aktarılır."},{"t":"Mayoz","a":"Çeşitli hücreler","d":"Mayoz sonunda oluşan hücreler genetik olarak farklı (çeşitli) olabilir. Krossing-over ve bağımsız dağılım bunu sağlar."}],"ans":"Mitoz özdeş hücreler, mayoz ise genetik olarak çeşitli hücreler oluşturur."},{"q":"Mitoz ve mayozun temel görevlerini karşılaştırınız.","steps":[{"t":"Mitoz görevi","a":"Büyüme-onarım-eşeysiz üreme","d":"Mitoz büyümeyi, yıpranan dokuların onarımını ve eşeysiz üremeyi sağlar. Vücudun sürekliliğini korur."},{"t":"Mayoz görevi","a":"Gamet oluşturma","d":"Mayoz gamet (üreme hücresi) oluşturarak eşeyli üremeyi sağlar. Türün devamlılığını ve çeşitliliğini destekler."}],"ans":"Mitoz büyüme-onarım-eşeysiz üreme, mayoz gamet oluşturma görevini üstlenir."},{"q":"Mitoz ve mayoz öncesinde DNA eşlenmesi açısından durumu karşılaştırınız.","steps":[{"t":"Mitoz öncesi","a":"1 kez eşlenir","d":"Mitozdan önce interfazda DNA bir kez eşlenir ve ardından tek bölünme gerçekleşir. Kromozom sayısı korunur."},{"t":"Mayoz öncesi","a":"1 kez eşlenir, 2 kez bölünür","d":"Mayozdan önce de DNA bir kez eşlenir ancak ardından iki kez bölünme olur. Bu yüzden kromozom sayısı yarıya iner."}],"ans":"Her ikisinde de DNA bir kez eşlenir; ancak mitozda 1, mayozda 2 bölünme olduğu için sonuçlar farklıdır."},{"q":"Mitozda homolog kromozomların eşleşmesi (sinapsis) görülür mü? Mayozla karşılaştırınız.","steps":[{"t":"Mitoz","a":"Sinapsis yok","d":"Mitozda homolog kromozomlar yan yana gelip eşleşmez. Her kromozom bağımsız hareket eder."},{"t":"Mayoz","a":"Sinapsis var","d":"Mayozda profaz I'de homolog kromozomlar eşleşerek tetrat oluşturur. Bu eşleşme krossing-overe olanak verir."}],"ans":"Mitozda sinapsis görülmez, mayozda (profaz I) homolog kromozomların sinapsisi görülür."},{"q":"Mitoz ve mayozun çok hücreli bir canlının yaşamındaki yerini karşılaştırınız.","steps":[{"t":"Mitoz","a":"Tüm yaşam boyu","d":"Mitoz, canlının zigottan itibaren büyümesi ve yaşam boyu doku yenilenmesi için sürekli gerçekleşir. Vücut hücrelerini çoğaltır."},{"t":"Mayoz","a":"Üreme döneminde","d":"Mayoz, üreme olgunluğuna ulaşıldığında eşey organlarında gerçekleşir. Yalnızca gamet üretiminde rol oynar."}],"ans":"Mitoz yaşam boyu büyüme-onarım için, mayoz ise üreme döneminde gamet üretimi için gerçekleşir."},{"q":"Diploid (2n) bir canlının gametlerinin mayozla oluşması neden zorunludur? Mitozla karşılaştırınız.","steps":[{"t":"Mitoz sonucu","a":"2n gamet olurdu","d":"Eğer gametler mitozla oluşsaydı 2n kromozomlu olurdu. Döllenmeyle kromozom sayısı 4n'e çıkardı."},{"t":"Mayoz sonucu","a":"n gamet","d":"Mayozla gametler haploid (n) oluşur. Döllenmeyle iki n gamet birleşince 2n'e ulaşılır."}],"ans":"Kromozom sayısının nesiller boyu 2n kalması için gametler mayozla oluşmalıdır; mitozla oluşsaydı sayı katlanırdı."},{"q":"Anafaz (mitoz) ile anafaz I (mayoz) sırasında ayrılan yapıları karşılaştırınız.","steps":[{"t":"Mitoz anafazı","a":"Kardeş kromatitler","d":"Mitoz anafazında her kromozomun kardeş kromatitleri ayrılarak zıt kutuplara gider. Sayı korunur."},{"t":"Anafaz I","a":"Homolog kromozomlar","d":"Mayoz anafaz I'de homolog kromozomlar birbirinden ayrılır, kardeş kromatitler birlikte kalır. Bu kromozom sayısını yarıya indirir."}],"ans":"Mitoz anafazında kardeş kromatitler, anafaz I'de ise homolog kromozomlar ayrılır."},{"q":"Mitoz ve mayozun bir canlıda aynı anda farklı hücrelerde gerçekleşip gerçekleşemeyeceğini açıklayınız.","steps":[{"t":"Vücut hücreleri","a":"Mitoz yapar","d":"Bir canlının vücut hücreleri büyüme ve onarım için sürekli mitoz geçirir. Bu her zaman olabilir."},{"t":"Eşey hücreleri","a":"Mayoz yapar","d":"Aynı canlının eşey organlarındaki ana hücreler ise mayoz geçirerek gamet üretir. Bu üreme döneminde gerçekleşir."}],"ans":"Evet; aynı canlıda vücut hücreleri mitoz, eşey ana hücreleri mayoz geçirebilir."},{"q":"Mitoz ve mayozda iğ ipliklerinin görevini karşılaştırınız.","steps":[{"t":"Mitozda","a":"Kromatitleri ayırır","d":"Mitozda iğ iplikleri kardeş kromatitleri zıt kutuplara çekerek eşit dağılımı sağlar. Tek bölünmede görev yapar."},{"t":"Mayozda","a":"İki kez görev","d":"Mayozda iğ iplikleri Mayoz I'de homologları, Mayoz II'de kardeş kromatitleri ayırır. İki bölünmede de çalışır."}],"ans":"İğ iplikleri her ikisinde de kromozomları kutuplara çeker; mitozda kardeş kromatitleri, mayozda hem homologları hem kromatitleri ayırır."},{"q":"Mitoz ve mayozun tür içi ve nesiller arası genetik kararlılığa katkısını karşılaştırınız.","steps":[{"t":"Mitoz katkısı","a":"Hücresel kararlılık","d":"Mitoz, vücut hücrelerinin genetik olarak özdeş kalmasını sağlar. Doku ve organların düzenli çalışmasını destekler."},{"t":"Mayoz katkısı","a":"Kromozom sayısı dengesi","d":"Mayoz, gametleri haploid yaparak döllenmeden sonra kromozom sayısının sabit kalmasını sağlar. Nesiller arası kararlılığı korur."}],"ans":"Mitoz hücreler arası genetik kararlılığı, mayoz ise gametleri haploid yaparak nesiller arası kromozom sayısı kararlılığını sağlar."},{"q":"Mitoz ve mayozun eşeysiz ve eşeyli üreme ile ilişkisini karşılaştırınız.","steps":[{"t":"Mitoz","a":"Eşeysiz üreme","d":"Mitoz, tek bir bireyin kendine özdeş kopyalar oluşturduğu eşeysiz üremede kullanılır. Yavrular ana bireyle aynıdır."},{"t":"Mayoz","a":"Eşeyli üreme","d":"Mayoz, iki gametin birleştiği eşeyli üremenin temelini oluşturur. Yavrular ebeveynlerden farklı olabilir."}],"ans":"Mitoz eşeysiz üremede özdeş bireyler, mayoz eşeyli üremede genetik olarak farklı bireyler oluşturur."}],"zor":[{"q":"Mitoz ve mayozun bölünme sayısı, hücre sayısı, kromozom sayısı ve genetik sonuç açısından dört temel farkını açıklayınız.","steps":[{"t":"Bölünme ve hücre","a":"1-2 ve 2-4","d":"Mitoz 1 bölünmeyle 2 hücre, mayoz 2 bölünmeyle 4 hücre oluşturur. Bölünme sayısı sonuç hücre sayısını belirler."},{"t":"Kromozom sayısı","a":"2n ve n","d":"Mitozda hücreler diploit (2n) kalırken mayozda haploit (n) hücreler oluşur. Mayoz kromozom sayısını yarıya indirir."},{"t":"Genetik sonuç","a":"Özdeş ve çeşitli","d":"Mitoz hücreleri özdeş, mayoz hücreleri ise genetik olarak çeşitlidir. Krossing-over ve bağımsız dağılım mayozda çeşitlilik sağlar."}],"ans":"Mitoz: 1 bölünme, 2 hücre, 2n, özdeş; Mayoz: 2 bölünme, 4 hücre, n, çeşitli."},{"q":"Krossing-over ve homolog kromozomların bağımsız dağılımının mayozda yarattığı çeşitliliği, mitozun özdeşliğiyle karşılaştırarak açıklayınız.","steps":[{"t":"Krossing-over","a":"Yeni gen kombinasyonu","d":"Mayoz profaz I'de homologlar arasındaki parça değişimi yeni gen kombinasyonları oluşturur. Bu mitozda bulunmaz."},{"t":"Bağımsız dağılım","a":"Rastgele ayrılma","d":"Metafaz I'de homolog çiftlerin rastgele dizilimi, gametlere farklı kromozom kombinasyonları dağıtır. Bu da çeşitliliği artırır."},{"t":"Mitozla fark","a":"Özdeşlik","d":"Mitozda bu olaylar yaşanmadığı için tüm hücreler özdeştir. Mayozda ise her gamet farklı olabilir."}],"ans":"Mayozda krossing-over ve bağımsız dağılım yeni kombinasyonlar oluşturarak çeşitlilik sağlarken, bu olayların olmadığı mitoz özdeş hücreler verir."},{"q":"2n=10 olan bir canlıda mitoz ve mayoz sonunda oluşan hücrelerin sayısını ve kromozom sayısını hesaplayarak karşılaştırınız.","steps":[{"t":"Mitoz sonucu","a":"2 hücre, 2n=10","d":"2n=10 olan hücre mitoz geçirince 2 hücre oluşur ve her birinde 10 kromozom bulunur. Kromozom sayısı korunur."},{"t":"Mayoz sonucu","a":"4 hücre, n=5","d":"Aynı hücre mayoz geçirince 4 hücre oluşur ve her birinde 5 kromozom bulunur. Kromozom sayısı yarıya iner."},{"t":"Karşılaştırma","a":"Sayısal fark","d":"Mitoz 2 hücre ve 2n=10, mayoz 4 hücre ve n=5 verir. Hücre sayısı ve kromozom sayısı açısından belirgin fark vardır."}],"ans":"Mitozda 2 hücre (her biri 2n=10), mayozda 4 hücre (her biri n=5) oluşur."},{"q":"Mitoz ve mayozun anafaz evrelerinde ayrılan yapıları (kardeş kromatit / homolog kromozom) karşılaştırarak kromozom sayısına etkisini açıklayınız.","steps":[{"t":"Mitoz anafazı","a":"Kardeş kromatit ayrılır","d":"Mitoz anafazında sentromerler bölünür ve kardeş kromatitler zıt kutuplara gider. Her kutba tam takım kromozom ulaşır, sayı korunur."},{"t":"Anafaz I","a":"Homolog ayrılır","d":"Mayoz anafaz I'de homolog kromozomlar ayrılır, kardeş kromatitler birlikte kalır. Bu kromozom sayısını yarıya indirir."},{"t":"Anafaz II","a":"Kardeş kromatit ayrılır","d":"Mayoz anafaz II'de kardeş kromatitler ayrılır, ancak hücre zaten haploittir. Sonuçta haploid hücreler korunur."}],"ans":"Mitoz anafazında kardeş kromatitler ayrılıp sayı korunur; mayoz anafaz I'de homologlar ayrılıp sayı yarıya iner, anafaz II'de kardeş kromatitler ayrılır."},{"q":"Mitoz ve mayozun gerçekleştiği hücreler ve görevleri bakımından bir türün hem sürekliliğini hem de çeşitliliğini nasıl sağladığını açıklayınız.","steps":[{"t":"Mitozun rolü","a":"Süreklilik","d":"Mitoz vücut hücrelerinde büyüme, onarım ve doku yenilenmesini sağlar. Bireyin sağlıklı yaşamını sürdürmesini mümkün kılar."},{"t":"Mayozun rolü","a":"Üreme ve çeşitlilik","d":"Mayoz eşey ana hücrelerinde gamet üreterek eşeyli üremeyi sağlar. Krossing-over ile genetik çeşitlilik oluşturur."},{"t":"Birlikte etki","a":"Tür devamlılığı","d":"Mitoz bireyin sürekliliğini, mayoz türün nesiller boyu çeşitlenerek devamını sağlar. İkisi birlikte yaşamın temelini oluşturur."}],"ans":"Mitoz vücut hücrelerini çoğaltarak bireyin sürekliliğini, mayoz gamet ve çeşitlilik oluşturarak türün devamını ve uyumunu sağlar."},{"q":"Mitoz ile mayozun DNA eşlenmesi ve bölünme sayısı ilişkisini, sonuçta oluşan DNA miktarı üzerinden karşılaştırınız.","steps":[{"t":"Mitoz","a":"Eşlenme + 1 bölünme","d":"Mitozda DNA bir kez eşlenir (2C → 4C) ve tek bölünme olur. Sonuçta hücreler 2C DNA miktarıyla ana hücreye eşit olur."},{"t":"Mayoz","a":"Eşlenme + 2 bölünme","d":"Mayozda DNA bir kez eşlenir (2C → 4C) ama iki bölünme olur. Her bölünmede DNA paylaşılır."},{"t":"Sonuç","a":"2C ve 1C","d":"Mitoz sonunda hücreler 2C, mayoz sonunda gametler 1C DNA içerir. Mayozda DNA miktarı çeyreğe iner."}],"ans":"Her ikisinde DNA bir kez eşlenir; mitoz tek bölünmeyle 2C'lik hücreler, mayoz iki bölünmeyle 1C'lik gametler verir."},{"q":"Mitoz ve mayoz arasındaki farkların evrimsel çeşitlilik açısından önemini açıklayınız.","steps":[{"t":"Mitozun katkısı","a":"Değişmezlik","d":"Mitoz genetik olarak değişmeyen hücreler üretir. Bu, organizmanın bütünlüğünü korur ama çeşitlilik sağlamaz."},{"t":"Mayozun katkısı","a":"Çeşitlilik","d":"Mayoz krossing-over ve bağımsız dağılımla yeni gen kombinasyonları oluşturur. Bu çeşitlilik popülasyona yeni özellikler kazandırır."},{"t":"Evrimsel önem","a":"Doğal seçilim malzemesi","d":"Mayozun yarattığı çeşitlilik, doğal seçilimin üzerinde çalışacağı varyasyonu sağlar. Bu da türlerin değişen koşullara uyum sağlamasını kolaylaştırır."}],"ans":"Mitoz değişmezlik sağlarken mayoz çeşitlilik oluşturur; bu çeşitlilik doğal seçilime malzeme sunarak evrimsel uyumu mümkün kılar."},{"q":"Bir hücrenin mayoz yerine yanlışlıkla mitoz geçirmesi, üreme hücresi üretimini nasıl etkilerdi? Karşılaştırarak açıklayınız.","steps":[{"t":"Beklenen (mayoz)","a":"n haploid gamet","d":"Eşey ana hücresinin mayoz geçirmesi haploid (n) gametler verir. Bu döllenme için zorunludur."},{"t":"Hatalı (mitoz)","a":"2n hücreler","d":"Eğer hücre mitoz geçirseydi 2n diploit hücreler oluşurdu. Bunlar gamet işlevi göremezdi."},{"t":"Sonuç","a":"Döllenme bozulur","d":"2n gametler döllenmeyle 4n zigot oluşturur ve kromozom sayısı dengesizleşir. Bu, üremeyi ve türün sürekliliğini bozardı."}],"ans":"Mayoz haploid gamet üretirken mitoz diploid hücreler verir; bu durumda gametler işlevsiz olur ve döllenmede kromozom sayısı dengesizleşir."},{"q":"Mitoz ve mayozun profaz evrelerini (profaz / profaz I) krossing-over ve sinapsis açısından karşılaştırınız.","steps":[{"t":"Mitoz profazı","a":"Sinapsis ve krossing-over yok","d":"Mitoz profazında homolog kromozomlar eşleşmez (sinapsis olmaz) ve krossing-over gerçekleşmez. Kromozomlar bağımsızdır."},{"t":"Profaz I","a":"Sinapsis ve krossing-over var","d":"Mayoz profaz I'de homolog kromozomlar eşleşip tetrat oluşturur (sinapsis) ve aralarında parça değişimi (krossing-over) olur. Bu çeşitlilik kaynağıdır."},{"t":"Sonuç","a":"Çeşitlilik farkı","d":"Mitoz profazı genetik değişim sağlamazken mayoz profaz I yeni gen kombinasyonları oluşturur. Bu, iki bölünme arasındaki temel genetik farktır."}],"ans":"Mitoz profazında sinapsis ve krossing-over yokken, mayoz profaz I'de homologlar eşleşip krossing-over gerçekleşir; bu mayoza özgü çeşitlilik sağlar."},{"q":"Mitozla bölünen bir kök hücre ile mayozla bölünen bir eşey ana hücresinin oluşturduğu hücrelerin işlevsel farkını açıklayınız.","steps":[{"t":"Kök hücre (mitoz)","a":"Özdeş vücut hücreleri","d":"Kök hücre mitozla bölünerek genetik olarak özdeş vücut hücreleri oluşturur. Bunlar dokuların yenilenmesini sağlar."},{"t":"Eşey ana hücresi (mayoz)","a":"Haploid gametler","d":"Eşey ana hücresi mayozla bölünerek haploid ve genetik olarak çeşitli gametler oluşturur. Bunlar üreme için kullanılır."},{"t":"İşlevsel fark","a":"Onarım ve üreme","d":"Mitoz ürünleri doku onarımı ve büyümede, mayoz ürünleri ise döllenme ve üremede görev alır. İşlevleri tamamen farklıdır."}],"ans":"Mitozla oluşan hücreler özdeş ve doku onarımı için, mayozla oluşan gametler haploid, çeşitli ve üreme için işlev görür."},{"q":"Mitoz ve mayozun anöploidi (kromozom sayısı hatası) riskini ayrılmama olayı üzerinden karşılaştırınız.","steps":[{"t":"Mitozda ayrılmama","a":"Doku hücrelerini etkiler","d":"Mitozda kardeş kromatitlerin ayrılmaması durumunda oluşan vücut hücreleri yanlış kromozom sayısına sahip olur. Bu lokal doku sorunlarına yol açabilir."},{"t":"Mayozda ayrılmama","a":"Gametleri etkiler","d":"Mayozda anafaz I veya II'de ayrılmama olursa gametler n+1 veya n-1 kromozomlu olur. Bu kalıtsal bozukluklara neden olur."},{"t":"Sonuç","a":"Kalıtsal etki farkı","d":"Mitozdaki hata bireyin bir bölümünü etkilerken mayozdaki hata döllenme yoluyla tüm yavruyu etkiler. Mayozdaki ayrılmama daha geniş kalıtsal sonuç doğurur."}],"ans":"Mitozda ayrılmama vücut hücrelerini lokal etkilerken, mayozda ayrılmama gametleri etkileyerek tüm yavruda kalıtsal kromozom hastalıklarına yol açar."},{"q":"2n=6 olan bir hücrenin mitoz metafazı ile mayoz metafaz I'deki kromozom dizilimlerini karşılaştırınız.","steps":[{"t":"Mitoz metafazı","a":"6 kromozom tek sıra","d":"Mitoz metafazında 2n=6 kromozomun tamamı ekvatorda tek sıra halinde dizilir. Her kromozom bağımsız durur."},{"t":"Metafaz I","a":"3 tetrat dizilir","d":"Mayoz metafaz I'de homolog kromozomlar eşleşip 3 tetrat (ikili grup) oluşturur ve ekvatorda karşılıklı dizilir. Diziliş ikili gruplar şeklindedir."},{"t":"Karşılaştırma","a":"Tekli ve ikili","d":"Mitozda kromozomlar tek tek, metafaz I'de ise homolog çiftler halinde dizilir. Bu dizilim farkı kromozom sayısının değişimini belirler."}],"ans":"Mitoz metafazında 6 kromozom tek sıra halinde dizilirken, metafaz I'de homologlar eşleşip 3 tetrat halinde karşılıklı dizilir."},{"q":"Mitoz ve mayoz sonucu oluşan hücrelerin döllenmeye katılma yeteneğini karşılaştırarak açıklayınız.","steps":[{"t":"Mitoz ürünleri","a":"Döllenemez","d":"Mitozla oluşan hücreler diploit (2n) vücut hücreleridir ve döllenmeye katılamaz. Görevleri büyüme ve onarımdır."},{"t":"Mayoz ürünleri","a":"Döllenebilir","d":"Mayozla oluşan haploid (n) gametler döllenmeye katılabilir. İki gamet birleşerek 2n zigot oluşturur."},{"t":"Sonuç","a":"Üreme yeteneği","d":"Sadece mayoz ürünleri eşeyli üremeyi sağlayabilir. Mitoz ürünleri bireyin kendi yaşamında görev yapar."}],"ans":"Mitoz ürünleri diploid vücut hücreleri olup döllenemez; mayoz ürünleri haploid gametlerdir ve döllenerek 2n zigot oluşturabilir."},{"q":"Mitoz ve mayozun kromozom sayısını koruma ve yarıya indirme mekanizmalarını, türün kromozom sayısının nesiller boyu sabit kalması açısından açıklayınız.","steps":[{"t":"Mitozun koruması","a":"2n sabit","d":"Mitoz kromozom sayısını değiştirmeden korur, böylece vücut hücreleri hep 2n kalır. Bu bireyin tüm hücrelerinde aynı kromozom sayısını sağlar."},{"t":"Mayozun indirmesi","a":"n gamet","d":"Mayoz gametlerin kromozom sayısını yarıya indirerek n yapar. Böylece döllenme öncesi sayı yarılanır."},{"t":"Nesil dengesi","a":"2n yeniden oluşur","d":"Döllenmede iki haploid gamet (n + n) birleşerek 2n zigot oluşturur. Böylece türün kromozom sayısı nesiller boyu sabit kalır."}],"ans":"Mitoz 2n'i korur, mayoz gametleri n yapar; döllenmeyle n+n=2n oluşarak türün kromozom sayısı nesiller boyu sabit kalır."},{"q":"Aynı genotipli iki kardeşin neden farklı, tek yumurta ikizlerinin neden aynı olduğunu mitoz ve mayoz farkıyla açıklayınız.","steps":[{"t":"Normal kardeşler","a":"Farklı gametler","d":"Normal kardeşler farklı mayoz ürünü gametlerin döllenmesiyle oluşur. Krossing-over ve bağımsız dağılım her gameti farklı kılar."},{"t":"Tek yumurta ikizleri","a":"Mitozla ayrılma","d":"Tek yumurta ikizleri, döllenmiş tek bir zigotun mitozla bölünüp ikiye ayrılmasıyla oluşur. Aynı genetik bilgiyi taşırlar."},{"t":"Sonuç","a":"Çeşitlilik ve özdeşlik","d":"Mayoz çeşitliliği nedeniyle kardeşler farklı, mitoz özdeşliği nedeniyle tek yumurta ikizleri aynıdır. İki bölünmenin genetik sonucu bu farkı açıklar."}],"ans":"Kardeşler farklı mayoz ürünü gametlerden oluştuğu için farklı; tek yumurta ikizleri tek zigotun mitozla ayrılmasıyla oluştuğu için özdeştir."}]}}};
